// This is a component — it is a function
function Greeting({ name }) {
  return <h1>Hello, {name}!</h1>;
}

// A component is a value — it can be assigned, passed, stored
const MyGreeting = Greeting; // same component, different name
const components = [Greeting, Button, Card]; // component in an array
const map = { greeting: Greeting }; // component in an object

// Class component — also a component (a class value)
class Greeting extends React.Component {
  render() {
    return <h1>Hello, {this.props.name}!</h1>;
  }
}

// Whether function or class, the key characteristic is the same:
// React calls it, passing props, and receives elements back

// Writing JSX creates an element
const el = <Greeting name="Alice" />;

// el is this plain object:
console.log(el);
// {
//   $$typeof: Symbol(react.element),
//   type: Greeting,       // reference to the function above
//   key: null,
//   ref: null,
//   props: { name: 'Alice' },
//   _owner: null
// }

typeof el  // 'object'
el.type    // the Greeting function itself
el.props   // { name: 'Alice' }

// 1. Component definition — happens once
function Counter({ initial }) {
  const [count, setCount] = React.useState(initial);
  // 2. During render, React calls Counter({initial: 0})
  // This function body runs and returns an element tree:
  return (
    <div>
      <p>Count: {count}</p>
      <button onClick={() => setCount(c => c + 1)}>+</button>
    </div>
  );
  // 3. React compares this element tree with the previous render's tree
  // 4. If count changed, React updates only the <p> text node
}

// Using the component creates an element — does NOT call Counter yet
const element = <Counter initial={0} />;
// element = { type: Counter, props: { initial: 0 }, ... }
// Counter has NOT been called at this point

// React.createRoot(...).render(element) triggers React to call Counter

// Creating the element — very cheap, just an object allocation
const el = <ExpensiveChart data={largeDataset} />;
// ExpensiveChart has not been called yet!

// React.memo wraps the component function
// It tells React: "skip calling this function if props didn't change"
const MemoizedChart = React.memo(ExpensiveChart);
const el2 = <MemoizedChart data={largeDataset} />;
// Still just an object allocation — MemoizedChart not called yet
// React checks props before deciding whether to call the wrapped function

// Render 1:
<div>
  <Input label="Name" />   {/* type: Input, key: null */}
</div>

// Render 2:
<div>
  <Input label="Email" />  {/* type: Input, key: null */}
</div>

// Same type (Input) and same key (null) at the same position
// → React reuses the existing Input instance, updates props to {label:'Email'}
// → State inside Input is PRESERVED

// Render 3:
<div>
  <Select label="Country" />  {/* type: Select — different! */}
</div>

// Different type (Select vs Input) at the same position
// → React unmounts Input, mounts a fresh Select
// → State is LOST

// Storing a component reference — OK, reusable
const ButtonComponent = Button;
function App() {
  return <ButtonComponent>Click</ButtonComponent>;
  // Stable type reference — React never remounts unnecessarily
}

// Storing an element — also OK, but it's a snapshot
const buttonElement = <Button>Click</Button>;
// This element is frozen — it always describes the same props
// React won't re-render it unless you call useState/etc

// TRAP: defining a component inside another component
function Parent() {
  // NEW function created on every Parent render!
  function InlineChild() {
    return <p>inner</p>;
  }
  // React sees a different type each render → full remount every time
  return <InlineChild />; // NEVER do this
}

// FIX: define outside
function InlineChild() { return <p>inner</p>; }
function Parent() {
  return <InlineChild />; // stable type reference — no remount
}

// Children — the most common form of element-as-prop
function Modal({ title, children }) {
  return (
    <div className="modal">
      <h2>{title}</h2>
      <div className="modal-body">{children}</div>
    </div>
  );
}

// Usage: the JSX inside <Modal> becomes children — an element or array of elements
<Modal title="Confirm">
  <p>Are you sure?</p>
  <Button>Yes</Button>
</Modal>

// Named slot pattern — pass elements as named props
function TwoColumn({ left, right }) {
  return (
    <div className="two-col">
      <aside>{left}</aside>
      <main>{right}</main>
    </div>
  );
}

// Usage: elements passed as ordinary props
<TwoColumn
  left={<Sidebar items={navItems} />}
  right={<ArticleList posts={posts} />}
/>

import React from 'react';

React.isValidElement(<div />);           // true
React.isValidElement(<Button />);        // true
React.isValidElement(Button);            // false — component, not element
React.isValidElement('hello');           // false — string
React.isValidElement({ type: 'div' });  // false — missing $$typeof

// Checking element type
function Wrapper({ children }) {
  React.Children.forEach(children, child => {
    if (React.isValidElement(child)) {
      console.log(child.type); // 'div', Button, etc.
    }
  });
  return <div>{children}</div>;
}

// You write:
function App() {
  return (
    <Layout>
      <Header title="My App" />
      <main>
        <Counter initial={0} />
      </main>
    </Layout>
  );
}

// React calls App(), gets an element tree:
// { type: Layout, props: { children: [
//     { type: Header, props: { title: 'My App' } },
//     { type: 'main', props: { children:
//         { type: Counter, props: { initial: 0 } }
//     }}
// ]}}

// React then calls Layout({children: ...}), Header({title:'My App'}), Counter({initial:0})
// Each returns more elements. React expands until all types are strings:
// { type: 'div', ... children: [
//     { type: 'header', ... children: 'My App' },
//     { type: 'main', ... children:
//         { type: 'div', ... children: [
//             { type: 'p', ... children: 'Count: 0' },
//             { type: 'button', ... children: '+' }
//         ]}
//     }
// ]}

// Component that accepts a render function as a prop
function DataFetcher({ url, render }) {
  const [data, setData] = useState(null);
  useEffect(() => {
    fetch(url).then(r => r.json()).then(setData);
  }, [url]);
  // Call the render function — it returns an element
  return render(data);
}

// Usage: pass a function that receives data and returns JSX
<DataFetcher
  url="/api/users"
  render={users => (
    <ul>
      {users?.map(u => <li key={u.id}>{u.name}</li>)}
    </ul>
  )}
/>

// Component factory — creates a specialized component
function makeColoredText(defaultColor) {
  // The returned component closes over defaultColor
  return function ColoredText({ color, children }) {
    const finalColor = color ?? defaultColor;
    return <span style={{ color: finalColor }}>{children}</span>;
  };
}

const RedText = makeColoredText('red');
const BlueText = makeColoredText('blue');

function App() {
  return (
    <>
      <RedText>Error!</RedText>
      <BlueText color="navy">Info</BlueText>
    </>
  );
}

// HOC — takes a component, returns a new component
function withLogging(WrappedComponent) {
  // Returns a component (a function)
  return function LoggedComponent(props) {
    console.log('Rendering:', WrappedComponent.name, 'with props:', props);
    return <WrappedComponent {...props} />;
    // <WrappedComponent {...props} /> creates an element at render time
  };
}

const LoggedButton = withLogging(Button);
// LoggedButton is a component (function), not an element

// Using it creates an element:
const el = <LoggedButton color="blue">Click</LoggedButton>;
// el = { type: LoggedComponent, props: { color: 'blue', children: 'Click' } }

import { lazy, Suspense } from 'react';

// lazy() returns a component (a lazy wrapper function)
const HeavyChart = lazy(() => import('./HeavyChart'));
// HeavyChart is a component — a lazy-loaded one

// Using it in JSX creates an element just like any other component
function Dashboard() {
  return (
    <Suspense fallback={<Spinner />}>
      <HeavyChart data={salesData} />
      {/* Element: { type: HeavyChart (lazy wrapper), props: { data: salesData } } */}
    </Suspense>
  );
}
// When React processes the HeavyChart element, it checks if the module is loaded
// If not, it suspends — Suspense catches and shows the fallback
// Once loaded, React calls the real chart component with the props
